import json, math
info = var_call_SxdZi8lVUdYiajqQHPGVF3wy
vols = var_call_CngkAMkBweND6UmLAw3KeoMC
map_desc = {rec['Symbol']: rec.get('Company Description') for rec in info}
result = []
for rec in vols:
    try:
        cnt = int(rec.get('cnt', 0))
    except:
        try:
            cnt = int(float(rec.get('cnt', 0)))
        except:
            cnt = 0
    if cnt > 0:
        sym = rec.get('Symbol')
        avg_raw = rec.get('avg_vol')
        try:
            avgf = float(avg_raw)
        except:
            avgf = None
        if avgf is None or (isinstance(avgf, float) and math.isnan(avgf)):
            continue
        desc = map_desc.get(sym)
        result.append({"Symbol": sym, "Company Description": desc, "avg_volume_2008": avgf})
result_sorted = sorted(result, key=lambda x: x['Symbol'])
print("__RESULT__:")
print(json.dumps(result_sorted))

